before_code:
module adder_8bit (
  input [7:0] a,
  input [7:0] b,
  input cin,
  output [7:0] sum,
  output cout
);
  assign {cout, sum} = a + b + cin;
endmodule

module top;
  wire [7:0] input_a, input_b;
  wire carry_in;
  wire [7:0] sum_out;
  wire carry_out;

  adder_8bit adder_inst (.a(input_a), .b(input_b), .cin(carry_in), .result(sum_out), .cout(carry_out));

endmodule

